"""Sprint68-1Bの4ファイルを完成版へ確実に全文置換する。"""

from __future__ import annotations

import base64
import inspect
from pathlib import Path

FILES = {
    Path('app/dashboard/dashboard_web_models.py'): '',
    Path('app/dashboard/dashboard_web_service.py'): '',
    Path('app/dashboard/templates/dashboard.html'): '',
    Path('app/dashboard/static/dashboard.css'): '',
}

for path, encoded in FILES.items():
    content = base64.b64decode(encoded)
    if path.suffix == '.py':
        compile(content.decode('utf-8'), str(path), 'exec')
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(content)
    print(f'updated: {path}')

from app.dashboard.dashboard_web_models import DashboardDailyPoint
from app.dashboard.dashboard_web_service import DashboardWebService

point_signature = inspect.signature(DashboardDailyPoint)
if 'drawdown' not in point_signature.parameters:
    raise RuntimeError('DashboardDailyPointへdrawdownが反映されていません。')

if not hasattr(DashboardWebService, '_create_daily_history'):
    raise RuntimeError('DashboardWebServiceの分析処理が反映されていません。')

css = Path('app/dashboard/static/dashboard.css').read_text(encoding='utf-8')
html = Path('app/dashboard/templates/dashboard.html').read_text(encoding='utf-8')

for marker in ('.chart-grid', '.line-series', '.bar-chart'):
    if marker not in css:
        raise RuntimeError(f'CSSへ{marker}が反映されていません。')

for marker in ('daily-pl-chart', 'cumulative-pl-chart', 'drawdown-chart'):
    if marker not in html:
        raise RuntimeError(f'HTMLへ{marker}が反映されていません。')

print('Sprint68-1B replacement completed successfully.')
print(point_signature)
